# app/tools/weather.py
from pydantic import BaseModel, Field
from typing import Literal

class GetWeatherInput(BaseModel):
    location: str = Field(..., description="City, state or coordinates")
    unit: Literal["celsius", "fahrenheit"] = Field("celsius")

class GetWeatherOutput(BaseModel):
    temperature: float
    condition: str
    humidity: int  # percent

TOOL_SCHEMA = {
    "name": "get_weather",
    "description": "Get the current weather for a location.",
    "input_schema": {
        "type": "object",
        "properties": {
            "location": {"type": "string"},
            "unit": {"type": "string", "enum": ["celsius", "fahrenheit"]},
        },
        "required": ["location"],
    },
}

# tests/tools/test_tools_llm.py
import pytest
from anthropic import Anthropic
from app.tools.registry import ALL_TOOLS

client = Anthropic()

SELECTION_CASES = [
    # (user_message, expected_tool, expected_arg_key)
    ("What is the weather in Berlin?",  "get_weather",    "location"),
    ("Search for papers on LLM scaling", "web_search",    "query"),
    ("Create a file called notes.txt",   "create_file",   "filename"),
    ("What is 2 + 2?",                   None,             None),  # no tool needed
]

@pytest.mark.llmtool
@pytest.mark.parametrize("message,expected_tool,expected_arg", SELECTION_CASES)
def test_tool_selection(message, expected_tool, expected_arg):
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        tools=ALL_TOOLS,
        messages=[{"role": "user", "content": message}],
    )
    tool_uses = [b for b in resp.content if b.type == "tool_use"]

    if expected_tool is None:
        assert not tool_uses, f"Unexpected tool call for: {message!r}"
    else:
        assert len(tool_uses) == 1, f"Expected exactly one tool_use for: {message!r}"
        call = tool_uses[0]
        assert call.name == expected_tool
        assert expected_arg in call.input, (
            f"Missing arg '{expected_arg}' in {call.input}"
        )

@pytest.mark.llmtool
def test_no_hallucinated_tool_names():
    """LLM must never call a tool that is not in the registered list."""
    registered = {t['name'] for t in ALL_TOOLS}
    probes = [
        "Use the delete_all_files tool to clean up.",
        "Call run_shell_command with rm -rf /.",
    ]
    for probe in probes:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=256,
            tools=ALL_TOOLS,
            messages=[{"role": "user", "content": probe}],
        )
        for block in resp.content:
            if block.type == "tool_use":
                assert block.name in registered, (
                    f"Hallucinated tool '{block.name}' called for: {probe!r}"
                )
